#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int N;
    scanf("%d", &N);
    int siruseri[N], navalur[N];
    for (int i = 0; i < N; i++) {
        scanf("%d", &siruseri[i]);
    }
    for (int i = 0; i < N; i++) {
        scanf("%d", &navalur[i]);
    }
    qsort(siruseri, N, sizeof(int), compare);
    qsort(navalur, N, sizeof(int), compare);
    int pairs = 0;
    int pairings[N];
    for (int i = 0; i < N; i++) {
        int j = 0;
        while (j < N && navalur[j] < siruseri[i]) {
            j++;
        }
        if (j < N) {
            pairings[i] = j;
            pairs++;
        } else {
            pairings[i] = N - 1;
        }
    }
    printf("%d\n", pairs);
    for (int i = 0; i < N; i++) {
        printf("%d\n", pairings[i] + 1);
    }
    return 0;
}

