        int N = scanner.nextInt();
        int[] siruseri = new int[N];
        int[] navalur = new int[N];
        for (int i = 0; i < N; i++) {
            siruseri[i] = scanner.nextInt();
        }
        for (int i = 0; i < N; i++) {
            navalur[i] = scanner.nextInt();
        }
        Arrays.sort(siruseri);
        Arrays.sort(navalur);
        int pairs = 0;
        int[] pairings = new int[N];
        for (int i = 0; i < N; i++) {
            int j = 0;
            while (j < N && navalur[j] < siruseri[i]) {
                j++;
            }
            if (j < N) {
